import React, { useState, useEffect, useRef } from 'react';
import { TweenMax, Expo, Power2, Quad } from 'gsap';

const AnimatedLogin = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [emailFocused, setEmailFocused] = useState(false);
  const [eyesCovered, setEyesCovered] = useState(false);
  const [mouthStatus, setMouthStatus] = useState('small');
  const [eyeScale, setEyeScale] = useState(1);
  const [showPasswordClicked, setShowPasswordClicked] = useState(false);

  // Referencias para los elementos SVG
  const mySVGRef = useRef(null);
  const emailRef = useRef(null);
  const armLRef = useRef(null);
  const armRRef = useRef(null);
  const eyeLRef = useRef(null);
  const eyeRRef = useRef(null);
  const noseRef = useRef(null);
  const mouthRef = useRef(null);
  const mouthBGRef = useRef(null);
  const mouthSmallBGRef = useRef(null);
  const mouthMediumBGRef = useRef(null);
  const mouthLargeBGRef = useRef(null);
  const mouthMaskPathRef = useRef(null);
  const mouthOutlineRef = useRef(null);
  const toothRef = useRef(null);
  const tongueRef = useRef(null);
  const chinRef = useRef(null);
  const faceRef = useRef(null);
  const eyebrowRef = useRef(null);
  const outerEarLRef = useRef(null);
  const outerEarRRef = useRef(null);
  const earHairLRef = useRef(null);
  const earHairRRef = useRef(null);
  const hairRef = useRef(null);

  let svgCoords = { x: 0, y: 0 };
  let emailCoords = { x: 0, y: 0 };
  let screenCenter = 0;
  let emailScrollMax = 0;
  let eyeLCoords = { x: 0, y: 0 };
  let eyeRCoords = { x: 0, y: 0 };
  let noseCoords = { x: 0, y: 0 };
  let mouthCoords = { x: 0, y: 0 };

  useEffect(() => {
    initLoginForm();
  }, []);

  const getPosition = (el) => {
    let xPos = 0;
    let yPos = 0;

    while (el) {
      if (el.tagName === "BODY") {
        const xScroll = el.scrollLeft || document.documentElement.scrollLeft;
        const yScroll = el.scrollTop || document.documentElement.scrollTop;
        xPos += (el.offsetLeft - xScroll + el.clientLeft);
        yPos += (el.offsetTop - yScroll + el.clientTop);
      } else {
        xPos += (el.offsetLeft - el.scrollLeft + el.clientLeft);
        yPos += (el.offsetTop - el.scrollTop + el.clientTop);
      }
      el = el.offsetParent;
    }
    return { x: xPos, y: yPos };
  };

  const initLoginForm = () => {
    if (!mySVGRef.current || !emailRef.current) return;
    
    svgCoords = getPosition(mySVGRef.current);
    emailCoords = getPosition(emailRef.current);
    screenCenter = svgCoords.x + (mySVGRef.current.offsetWidth / 2);
    eyeLCoords = { x: svgCoords.x + 84, y: svgCoords.y + 76 };
    eyeRCoords = { x: svgCoords.x + 113, y: svgCoords.y + 76 };
    noseCoords = { x: svgCoords.x + 97, y: svgCoords.y + 81 };
    mouthCoords = { x: svgCoords.x + 100, y: svgCoords.y + 100 };

    // Set initial arm positions
    TweenMax.set(armLRef.current, {
      x: -93,
      y: 220,
      rotation: 105,
      transformOrigin: "top left"
    });
    TweenMax.set(armRRef.current, {
      x: -93,
      y: 220,
      rotation: -105,
      transformOrigin: "top right"
    });

    // Start blinking
    startBlinking(5);

    emailScrollMax = emailRef.current.scrollWidth;
  };

  const startBlinking = (delay) => {
    if (delay) {
      delay = Math.floor(Math.random() * Math.floor(delay));
    } else {
      delay = 1;
    }
    
    TweenMax.to([eyeLRef.current, eyeRRef.current], 0.1, {
      delay: delay,
      scaleY: 0,
      yoyo: true,
      repeat: 1,
      transformOrigin: "center center",
      onComplete: () => startBlinking(12)
    });
  };

  const calculateFaceMove = (e) => {
    const carPos = e.target.selectionEnd;
    const div = document.createElement('div');
    const span = document.createElement('span');
    const copyStyle = getComputedStyle(e.target);
    let caretCoords = {};

    [].forEach.call(copyStyle, (prop) => {
      div.style[prop] = copyStyle[prop];
    });

    div.style.position = 'absolute';
    document.body.appendChild(div);
    div.textContent = e.target.value.substr(0, carPos);
    span.textContent = e.target.value.substr(carPos) || '.';
    div.appendChild(span);

    if (e.target.scrollWidth <= emailScrollMax) {
      caretCoords = getPosition(span);
      const dFromC = screenCenter - (caretCoords.x + emailCoords.x);
      const eyeLAngle = getAngle(eyeLCoords.x, eyeLCoords.y, emailCoords.x + caretCoords.x, emailCoords.y + 25);
      const eyeRAngle = getAngle(eyeRCoords.x, eyeRCoords.y, emailCoords.x + caretCoords.x, emailCoords.y + 25);
      const noseAngle = getAngle(noseCoords.x, noseCoords.y, emailCoords.x + caretCoords.x, emailCoords.y + 25);
      const mouthAngle = getAngle(mouthCoords.x, mouthCoords.y, emailCoords.x + caretCoords.x, emailCoords.y + 25);

      const eyeLX = Math.cos(eyeLAngle) * 20;
      const eyeLY = Math.sin(eyeLAngle) * 10;
      const eyeRX = Math.cos(eyeRAngle) * 20;
      const eyeRY = Math.sin(eyeRAngle) * 10;
      const noseX = Math.cos(noseAngle) * 23;
      const noseY = Math.sin(noseAngle) * 10;
      const mouthX = Math.cos(mouthAngle) * 23;
      const mouthY = Math.sin(mouthAngle) * 10;
      const mouthR = Math.cos(mouthAngle) * 6;
      const chinX = mouthX * .8;
      const chinY = mouthY * .5;
      const chinS = 1 - ((dFromC * .15) / 100);
      const faceX = mouthX * .3;
      const faceY = mouthY * .4;
      const faceSkew = Math.cos(mouthAngle) * 5;
      const eyebrowSkew = Math.cos(mouthAngle) * 25;
      const outerEarX = Math.cos(mouthAngle) * 4;
      const outerEarY = Math.cos(mouthAngle) * 5;
      const hairX = Math.cos(mouthAngle) * 6;
      const hairS = 1.2;

      TweenMax.to(eyeLRef.current, 1, { x: -eyeLX, y: -eyeLY, ease: Expo.easeOut });
      TweenMax.to(eyeRRef.current, 1, { x: -eyeRX, y: -eyeRY, ease: Expo.easeOut });
      TweenMax.to(noseRef.current, 1, { x: -noseX, y: -noseY, rotation: mouthR, transformOrigin: "center center", ease: Expo.easeOut });
      TweenMax.to(mouthRef.current, 1, { x: -mouthX, y: -mouthY, rotation: mouthR, transformOrigin: "center center", ease: Expo.easeOut });
      TweenMax.to(chinRef.current, 1, { x: -chinX, y: -chinY, scaleY: chinS, ease: Expo.easeOut });
      TweenMax.to(faceRef.current, 1, { x: -faceX, y: -faceY, skewX: -faceSkew, transformOrigin: "center top", ease: Expo.easeOut });
      TweenMax.to(eyebrowRef.current, 1, { x: -faceX, y: -faceY, skewX: -eyebrowSkew, transformOrigin: "center top", ease: Expo.easeOut });
      TweenMax.to(outerEarLRef.current, 1, { x: outerEarX, y: -outerEarY, ease: Expo.easeOut });
      TweenMax.to(outerEarRRef.current, 1, { x: outerEarX, y: outerEarY, ease: Expo.easeOut });
      TweenMax.to(earHairLRef.current, 1, { x: -outerEarX, y: -outerEarY, ease: Expo.easeOut });
      TweenMax.to(earHairRRef.current, 1, { x: -outerEarX, y: outerEarY, ease: Expo.easeOut });
      TweenMax.to(hairRef.current, 1, { x: hairX, scaleY: hairS, transformOrigin: "center bottom", ease: Expo.easeOut });
    }

    document.body.removeChild(div);
  };

  const onEmailInput = (e) => {
    calculateFaceMove(e);
    const value = e.target.value;
    const curEmailIndex = value.length;

    if (curEmailIndex > 0) {
      if (mouthStatus === "small") {
        setMouthStatus("medium");
        TweenMax.to([mouthBGRef.current, mouthOutlineRef.current, mouthMaskPathRef.current], 1, {
          morphSVG: mouthMediumBGRef.current,
          shapeIndex: 8,
          ease: Expo.easeOut
        });
        TweenMax.to(toothRef.current, 1, { x: 0, y: 0, ease: Expo.easeOut });
        TweenMax.to(tongueRef.current, 1, { x: 0, y: 1, ease: Expo.easeOut });
        TweenMax.to([eyeLRef.current, eyeRRef.current], 1, { scaleX: .85, scaleY: .85, ease: Expo.easeOut });
        setEyeScale(.85);
      }
      if (value.includes("@")) {
        setMouthStatus("large");
        TweenMax.to([mouthBGRef.current, mouthOutlineRef.current, mouthMaskPathRef.current], 1, {
          morphSVG: mouthLargeBGRef.current,
          ease: Expo.easeOut
        });
        TweenMax.to(toothRef.current, 1, { x: 3, y: -2, ease: Expo.easeOut });
        TweenMax.to(tongueRef.current, 1, { y: 2, ease: Expo.easeOut });
        TweenMax.to([eyeLRef.current, eyeRRef.current], 1, {
          scaleX: .65,
          scaleY: .65,
          ease: Expo.easeOut,
          transformOrigin: "center center"
        });
        setEyeScale(.65);
      } else {
        setMouthStatus("medium");
        TweenMax.to([mouthBGRef.current, mouthOutlineRef.current, mouthMaskPathRef.current], 1, {
          morphSVG: mouthMediumBGRef.current,
          ease: Expo.easeOut
        });
      }
    } else {
      setMouthStatus("small");
      TweenMax.to([mouthBGRef.current, mouthOutlineRef.current, mouthMaskPathRef.current], 1, {
        morphSVG: mouthSmallBGRef.current,
        shapeIndex: 9,
        ease: Expo.easeOut
      });
      TweenMax.to(toothRef.current, 1, { x: 0, y: 0, ease: Expo.easeOut });
      TweenMax.to(tongueRef.current, 1, { y: 0, ease: Expo.easeOut });
      TweenMax.to([eyeLRef.current, eyeRRef.current], 1, { scaleX: 1, scaleY: 1, ease: Expo.easeOut });
      setEyeScale(1);
    }
  };

  const coverEyes = () => {
    TweenMax.killTweensOf([armLRef.current, armRRef.current]);
    TweenMax.set([armLRef.current, armRRef.current], { visibility: "visible" });
    TweenMax.to(armLRef.current, .45, { x: -93, y: 10, rotation: 0, ease: Quad.easeOut });
    TweenMax.to(armRRef.current, .45, { x: -93, y: 10, rotation: 0, ease: Quad.easeOut, delay: .1 });
    setEyesCovered(true);
  };

  const uncoverEyes = () => {
    TweenMax.killTweensOf([armLRef.current, armRRef.current]);
    TweenMax.to(armLRef.current, 1.35, { y: 220, ease: Quad.easeOut });
    TweenMax.to(armLRef.current, 1.35, { rotation: 105, ease: Quad.easeOut, delay: .1 });
    TweenMax.to(armRRef.current, 1.35, { y: 220, ease: Quad.easeOut });
    TweenMax.to(armRRef.current, 1.35, { rotation: -105, ease: Quad.easeOut, delay: .1 });
    setEyesCovered(false);
  };

  const getAngle = (x1, y1, x2, y2) => {
    const angle = Math.atan2(y2 - y1, x2 - x1);
    return angle;
  };

  const onPasswordFocus = () => {
    coverEyes();
  };

  const onPasswordBlur = () => {
    uncoverEyes();
  };

  return (
    <div className="w-full max-w-md mx-auto p-6">
      <div className="relative">
        <svg
          ref={mySVGRef}
          className="mx-auto"
          viewBox="0 0 200 200"
          width="200"
          height="200"
        >
          {/* Character face */}
          <g ref={faceRef}>
            <circle fill="#000" cx="100" cy="100" r="50" />
            {/* Add other facial features using the refs */}
            <circle ref={eyeLRef} fill="#fff" cx="84" cy="76" r="5" />
            <circle ref={eyeRRef} fill="#fff" cx="113" cy="76" r="5" />
            <path ref={noseRef} fill="#fff" d="M97,81 L102,81 L99.5,84 Z" />
            <g ref={mouthRef}>
              <path
                ref={mouthBGRef}
                fill="#fff"
                d="M100,100 C105,100 110,100 110,105 C110,110 105,110 100,110 C95,110 90,110 90,105 C90,100 95,100 100,100"
              />
              <path
                ref={mouthSmallBGRef}
                fill="#fff"
                d="M100,100 C103,100 106,100 106,103 C106,106 103,106 100,106 C97,106 94,106 94,103 C94,100 97,100 100,100"
              />
              <path
                ref={mouthMediumBGRef}
                fill="#fff"
                d="M100,100 C106,100 112,100 112,106 C112,112 106,112 100,112 C94,112 88,112 88,106 C88,100 94,100 100,100"
              />
              <path
                ref={mouthLargeBGRef}
                fill="#fff"
                d="M100,100 C108,100 116,100 116,108 C116,116 108,116 100,116 C92,116 84,116 84,108 C84,100 92,100 100,100"
              />
              <path
                ref={mouthMaskPathRef}
                fill="none"
                d="M100,100 C105,100 110,100 110,105 C110,110 105,110 100,110 C95,110 90,110 90,105 C90,100 95,100 100,100"
              />
              <path ref={mouthOutlineRef} fill="none" stroke="#000" strokeWidth="1" d="M100,100 C105,100 110,100 110,105 C110,110 105,110 100,110 C95,110 90,110 90,105 C90,100 95,100 100,100" />
              <path ref={tongueRef} fill="#ff3366" d="M98,105 L102,105 L100,108 Z" />
              <path ref={toothRef} fill="#fff" stroke="#000" strokeWidth="0.5" d="M100,103 L102,103 L101,105 Z" />
            </g>
          </g>
          {/* Arms */}
          <path ref={armLRef} fill="#000" d="M50,220 L75,220 L65,105 L40,105 Z" />
          <path ref={armRRef} fill="#000" d="M150,220 L125,220 L135,105 L160,105 Z" />
        </svg>
        
        <form className="mt-8 space-y-4">
          <div>
            <input
              ref={emailRef}
              type="email"
              value={email}
              onChange={(e) => {
                setEmail(e.target.value);
                onEmailInput(e);
              }}
              onFocus={() => setEmailFocused(true)}
              onBlur={() => setEmailFocused(false)}
              className="w-full px-4 py-2 border rounded"
              placeholder="Email"
            />
          </div>
          <div>
            <input
              type={showPassword ? "text" : "password"}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              onFocus={onPasswordFocus}
              onBlur={onPasswordBlur}
              className="w-full px-4 py-2 border rounded"
              placeholder="Password"
            />
          </div>
          <button
            type="submit"
            className="w-full px-4 py-2 text-white bg-blue-600 rounded hover:bg-blue-700"
          >
            Login
          </button>
        </form>
      </div>
    </div>
  );
};

export default AnimatedLogin;
